import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { HeistTimerParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/HeistTimerParser';

export class HeistTimerEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, HeistTimerParser);
}

public getParser(): HeistTimerParser
{
return this.parser as HeistTimerParser;
}
}